-- ============================================================
-- life-os — Row Level Security Policies
-- Generated by: Dara (@data-engineer)
-- Date: 2026-02-20
-- Applies to: All user-data tables in Supabase PostgreSQL
-- ============================================================
--
-- PATTERN: Every table with user_id uses the KISS RLS policy:
--   SELECT/INSERT/UPDATE/DELETE: user_id = auth.uid()
--
-- EXCEPTIONS:
--   workflow_templates: SELECT open to all authenticated users (system templates)
--   correlations: SELECT/INSERT by user, no UPDATE (immutable results)
--
-- APPLY ORDER: Enable RLS first, then create policies.
-- ============================================================

-- ── HELPER: Updated At trigger function ─────────────────────────────────────

CREATE OR REPLACE FUNCTION update_updated_at_column()
RETURNS TRIGGER AS $$
BEGIN
  NEW.updated_at = NOW();
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- ── 1. areas ─────────────────────────────────────────────────────────────────

ALTER TABLE areas ENABLE ROW LEVEL SECURITY;

CREATE POLICY "areas: user owns their areas"
  ON areas FOR ALL
  USING (user_id = auth.uid())
  WITH CHECK (user_id = auth.uid());

CREATE TRIGGER areas_updated_at
  BEFORE UPDATE ON areas
  FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();

-- ── 2. area_scores ───────────────────────────────────────────────────────────

ALTER TABLE area_scores ENABLE ROW LEVEL SECURITY;

CREATE POLICY "area_scores: user owns their scores"
  ON area_scores FOR ALL
  USING (user_id = auth.uid())
  WITH CHECK (user_id = auth.uid());

-- No updated_at trigger — area_scores are immutable (append-only)

-- ── 3. okrs ──────────────────────────────────────────────────────────────────

ALTER TABLE okrs ENABLE ROW LEVEL SECURITY;

CREATE POLICY "okrs: user owns their OKRs"
  ON okrs FOR ALL
  USING (user_id = auth.uid())
  WITH CHECK (user_id = auth.uid());

CREATE TRIGGER okrs_updated_at
  BEFORE UPDATE ON okrs
  FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();

-- ── 4. workflow_templates ────────────────────────────────────────────────────

ALTER TABLE workflow_templates ENABLE ROW LEVEL SECURITY;

-- System templates: all authenticated users can read
CREATE POLICY "workflow_templates: read system templates"
  ON workflow_templates FOR SELECT
  USING (is_system = true AND auth.uid() IS NOT NULL);

-- User-created templates: user owns their own
CREATE POLICY "workflow_templates: user owns custom templates"
  ON workflow_templates FOR ALL
  USING (is_system = false AND user_id = auth.uid())
  WITH CHECK (is_system = false AND user_id = auth.uid());

