-- ── 15. correlations ─────────────────────────────────────────────────────────

ALTER TABLE correlations ENABLE ROW LEVEL SECURITY;

-- SELECT + INSERT only (nightly cron uses service_role for INSERT)
CREATE POLICY "correlations: user can read their correlations"
  ON correlations FOR SELECT
  USING (user_id = auth.uid());

-- Note: INSERT is performed by the Edge Function cron using service_role key.
-- service_role bypasses RLS — no INSERT policy needed for the cron job.
-- If you ever need user-initiated correlation requests, add an INSERT policy.

-- ── FK: auth.users cascade deletes ──────────────────────────────────────────
--
-- Add FK constraints from user_id to auth.users(id) for cascade delete.
-- This ensures all user data is deleted when a user account is deleted.
-- Drizzle does NOT manage cross-schema FKs — add manually here.
--
-- Execute AFTER all tables are created:

ALTER TABLE areas
  ADD CONSTRAINT areas_user_id_fkey
  FOREIGN KEY (user_id) REFERENCES auth.users(id) ON DELETE CASCADE;

ALTER TABLE okrs
  ADD CONSTRAINT okrs_user_id_fkey
  FOREIGN KEY (user_id) REFERENCES auth.users(id) ON DELETE CASCADE;

ALTER TABLE projects
  ADD CONSTRAINT projects_user_id_fkey
  FOREIGN KEY (user_id) REFERENCES auth.users(id) ON DELETE CASCADE;

ALTER TABLE workflows
  ADD CONSTRAINT workflows_user_id_fkey
  FOREIGN KEY (user_id) REFERENCES auth.users(id) ON DELETE CASCADE;

ALTER TABLE tasks
  ADD CONSTRAINT tasks_user_id_fkey
  FOREIGN KEY (user_id) REFERENCES auth.users(id) ON DELETE CASCADE;

ALTER TABLE habits
  ADD CONSTRAINT habits_user_id_fkey
  FOREIGN KEY (user_id) REFERENCES auth.users(id) ON DELETE CASCADE;

ALTER TABLE skills
  ADD CONSTRAINT skills_user_id_fkey
  FOREIGN KEY (user_id) REFERENCES auth.users(id) ON DELETE CASCADE;

ALTER TABLE steps_activities
  ADD CONSTRAINT steps_activities_user_id_fkey
  FOREIGN KEY (user_id) REFERENCES auth.users(id) ON DELETE CASCADE;

ALTER TABLE time_entries
  ADD CONSTRAINT time_entries_user_id_fkey
  FOREIGN KEY (user_id) REFERENCES auth.users(id) ON DELETE CASCADE;

ALTER TABLE inbox_items
  ADD CONSTRAINT inbox_items_user_id_fkey
  FOREIGN KEY (user_id) REFERENCES auth.users(id) ON DELETE CASCADE;

ALTER TABLE checkin_responses
  ADD CONSTRAINT checkin_responses_user_id_fkey
  FOREIGN KEY (user_id) REFERENCES auth.users(id) ON DELETE CASCADE;

ALTER TABLE step_skill_tags
  ADD CONSTRAINT step_skill_tags_user_id_fkey
  FOREIGN KEY (user_id) REFERENCES auth.users(id) ON DELETE CASCADE;

ALTER TABLE correlations
  ADD CONSTRAINT correlations_user_id_fkey
  FOREIGN KEY (user_id) REFERENCES auth.users(id) ON DELETE CASCADE;

ALTER TABLE area_scores
  ADD CONSTRAINT area_scores_user_id_fkey
  FOREIGN KEY (user_id) REFERENCES auth.users(id) ON DELETE CASCADE;

-- ── Supabase Auth trigger: seed areas on user signup ────────────────────────
--
-- When a new user signs up, automatically create their 8 Maslow areas.
-- Executed via Supabase Auth Hook (Database Webhook on auth.users INSERT).

CREATE OR REPLACE FUNCTION seed_user_areas()
RETURNS TRIGGER AS $$
BEGIN
  INSERT INTO areas (user_id, maslow_level, "group", name, default_name, weight_multiplier) VALUES
    (NEW.id, 1, 'd_needs', 'Fisiológica',       'Fisiológica',       '2.0'),
    (NEW.id, 2, 'd_needs', 'Seguridad',          'Seguridad',          '2.0'),
    (NEW.id, 3, 'd_needs', 'Conexión Social',    'Conexión Social',    '1.5'),
    (NEW.id, 4, 'd_needs', 'Estima',             'Estima',             '1.5'),
    (NEW.id, 5, 'b_needs', 'Cognitiva',          'Cognitiva',          '1.2'),
    (NEW.id, 6, 'b_needs', 'Estética',           'Estética',           '1.2'),
    (NEW.id, 7, 'b_needs', 'Autorrealización',   'Autorrealización',   '1.0'),
    (NEW.id, 8, 'b_needs', 'Autotrascendencia',  'Autotrascendencia',  '1.0');
  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- Register the trigger on auth.users
CREATE TRIGGER on_auth_user_created
  AFTER INSERT ON auth.users
  FOR EACH ROW EXECUTE FUNCTION seed_user_areas();

